        wGm_.SetGlobalBuffer((__gm__ float*)weight, C_out * C_in * kernel_h * kernel_w);
        yGm_.SetGlobalBuffer((__gm__ float*)y, N * C_out * H_out * W_out);

        conv_.SetInput(xGm_, {N, C_in, H_in, W_in}, FORMAT_NCHW);
        conv_.SetWeight(wGm_, {C_out, C_in, kernel_h, kernel_w}, FORMAT_NCHW);
        conv_.SetOutput(yGm_, {N, C_out, H_out, W_out}, FORMAT_NCHW);

        conv_.SetPad(pad_h, pad_w, pad_h, pad_w);
        conv_.SetStride(stride_h, stride_w);
        conv_.SetDilation(dilation_h, dilation_w);
    }

